INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GATE', 'GATE', 'L’écosystème aéronautique marocain représente l’un des plus beaux cas de réussite industrielle dans un pays en développement avec un important besoin en ingénieurs diplômés. Ainsi le Maroc est devenu un important acteur dans ce secteur industriel. Avec la présence des leaders du secteur aéronautique sur son sol, tels que Bombardier, EADS, Boeing, Safran, Thalès, le Maroc a fait du secteur aéronautique un des plus importants dans son Plan d’accélération industriel 2014-2020. Le métier d’ingénieur aéronautique fait appel à des qualifications issues de multiples disciplines : physique, matériaux, informatique, mécanique, hydraulique, pneumatique, électronique, armement…Il travaille donc en équipe multidisciplinaire et internationalisée( anglais requis). Notre filière de spécialisation met la théorie en pratique de façon équilibrée et mène à un diplôme d’ingénierie en techniques aéronautique et aérospatiale, en Techniques de maintenance d''aéronefs ou en Techniques d''avionique, en plus, la formation est dotée de reconnaissance des codes et des normes de l''aviation civile nationales, européennes et de l''UAE. Par ailleurs Notre diplôme offre la possibilité à ses étudiants de passer les examens PART-66 de l’Agence européenne de sécurité aérienne (EASA) afin d’obtenir une licence de maintenance d’aéronefs (LMA) européenne en collaboration avec le NOVAe Aerospace. Cette filière est bien appuyée par des professionnels du domaines aéronautiques et spatiales à l’échelle nationale (CE3M, GIMAS…) et aussi internationale (NOVAE ,HCT …). Et dans son opérationnalisation plusieurs intervenants du monde de l’industrie vont animer et assister les apprentissages aux futures ingénieurs.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Structures des avions, Technologies des aéronefs", "type": "common"}, {"name": "Fonctions électroniques", "type": "common"}, {"name": "Mécanique des fluides appliquée", "type": "common"}, {"name": "Matériaux plastiques et composites", "type": "common"}, {"name": "Thermopropulsion", "type": "common"}, {"name": "Langues étrangères 1 (Anglais/Français)", "type": "common"}, {"name": "Algorithmique et Programmation en Python", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Conception aéronautique et Design Industriel", "type": "common"}, {"name": "Systèmes embarqués 1", "type": "common"}, {"name": "Système d''information", "type": "common"}, {"name": "Programmation pour l''ingénieur", "type": "common"}, {"name": "Analyse numérique / Equations Différentielles", "type": "common"}, {"name": "Langues étrangères 2 (Anglais/Français)", "type": "common"}, {"name": "Culture and Art Skills", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Commande des systèmes électriques des aéronefs", "type": "common"}, {"name": "Systèmes embarqués II", "type": "common"}, {"name": "Technologie des hélices", "type": "common"}, {"name": "Mécanique du vol et aérodynamique appliquée", "type": "common"}, {"name": "Technologies propulseurs et Moteurs à piston", "type": "common"}, {"name": "Langues étrangères 3 (Anglais/Français)", "type": "common"}, {"name": "Intelligence Artificielle et ses Applications", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Hydraulique, Pneumatique / Météorologie aéronautique", "type": "common"}, {"name": "Calcul des structures en aéronautique", "type": "common"}, {"name": "CFAO et Machines Outils à commande", "type": "common"}, {"name": "Lean six sigma et Manufacturing", "type": "common"}, {"name": "Recherche opérationnelle, Optimisation et Modélisation", "type": "common"}, {"name": "Langues étrangères 4 (Anglais/Français)", "type": "common"}, {"name": "Management de projet et Entrepre- nariat", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Management Organisationnel et Management de Projets Complexes", "type": "common"}, {"name": "Smart manufacturing : Industrie 4.0", "type": "common"}, {"name": "Logistique Industrielle", "type": "common"}, {"name": "Aircraft Maintenance Practices", "type": "common"}, {"name": "Qualité, Sécurité et Environnement et réglementation aéronautique", "type": "common"}, {"name": "Langues étrangères 5 (Anglais/Français)", "type": "common"}, {"name": "Employment Skills", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'ingénieur aéronautique, ingénieur interface client aéronautique, ingénieur études aéronautiques, consultant aerospace, ingénieur systèmes aéronautiques, ingénieur logiciel embarqué aéronautique, ingénieur assistance technique.', 'Aéronautique, Technologies spatiales, maintenance aéronautique, manufacturing aéronautique, smart-manufacturing.');
INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GIIA', 'GIIA', NULL, '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Ingénierie Financière", "type": "common"}, {"name": "Mathématiques pour l''Ingénieur", "type": "common"}, {"name": "Python pour la Data Science et le Machine Learning", "type": "common"}, {"name": "Systèmes d''Information", "type": "common"}, {"name": "Modélisation Stochastique", "type": "common"}, {"name": "Systèmes de Gestion de Contenu", "type": "common"}, {"name": "LC 1", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Transition Écologique et Dynamiques Culturelles", "type": "common"}, {"name": "Techniques d''Optimisation Avancées", "type": "common"}, {"name": "Systèmes d''Exploitation et Environnements de Développement", "type": "common"}, {"name": "Modélisation UML", "type": "common"}, {"name": "Architecture des Systèmes", "type": "common"}, {"name": "Machine Learning", "type": "common"}, {"name": "LC 2", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Développement Backend en JS", "type": "gi"}, {"name": "Marketing et Développement Durable", "type": "common"}, {"name": "Bases de Données Avancées", "type": "common"}, {"name": "Méthodes Heuristiques et Méta-Heuristiques", "type": "gidia"}, {"name": "Projets Tutorés", "type": "common"}, {"name": "Analyse des Données", "type": "gidia"}, {"name": "Programmation Java Avancée", "type": "gi"}, {"name": "Développement Web Dynamique", "type": "gi"}, {"name": "LC 3", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Gouvernance des Systèmes d''Information", "type": "gi"}, {"name": "Génie Logiciel", "type": "gi"}, {"name": "Systèmes Intelligents Flous", "type": "gidia"}, {"name": "Traitement d''Image / Vision Artificielle", "type": "common"}, {"name": "Internet des Objets", "type": "common"}, {"name": "Cloud Computing et Virtualisation", "type": "common"}, {"name": "Introduction à la Sécurité des Réseaux et Systèmes", "type": "common"}, {"name": "Management de Projet et Entrepreneuriat", "type": "common"}, {"name": "LC 4", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Architectures Réparties JEE", "type": "gi"}, {"name": "Ingénierie des Données Massives et Big Data", "type": "gidia"}, {"name": "Anglais", "type": "common"}, {"name": "Traitement Automatique du Langage Naturel", "type": "gidia"}, {"name": "Théorie des Jeux et Systèmes Multi-Agents", "type": "gidia"}, {"name": "Web Sémantique et Développement Mobile", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Intégration et Solutions Métiers", "type": "common"}, {"name": "E-Management et Innovation / Innovation et Entrepreneuriat", "type": "common"}, {"name": "Sécurité des Systèmes d''Information et Technologie Blockchain", "type": "common"}, {"name": "Factory Management / Usine de Développement Logiciel", "type": "gi"}, {"name": "Projet de Fin d''Études", "type": "common"}]}]}]', NULL, NULL);
INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GINDUS', 'GINDUS', 'L''objectif de cette formation est de doter les ingénieurs en génie industriel des compétences nécessaires en management industriel. Le métier de l''ingénieur en génie industriel repose sur l''amélioration continue et l''optimisation des performances des entreprises dans divers domaines (technique, financier, organisationnel, humain). La formation répond à cette polyvalence en proposant, durant les trois premiers semestres, des enseignements techniques et scientifiques (électronique, informatique, mécanique, ... etc), suivis de formations managériales et spécifiques (production, maintenance, qualité, logistique, lean manufacturing,...etc) dans les deux derniers semestres. L''enjeu est de fournir aux futurs ingénieurs les outils et méthodes pour concevoir des systèmes et gérer efficacement les aspects économiques, financiers, humains et matériels des entreprises.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Conception des systèmes mécaniques", "type": "common"}, {"name": "Systèmes de mesure et conception expérimentale", "type": "common"}, {"name": "Thermodynamique appliquée et phénomènes de transfert", "type": "common"}, {"name": "Calcul des structures", "type": "common"}, {"name": "Sciences des matériaux", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Excel avancé", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Machines électriques et électronique de puissance", "type": "common"}, {"name": "Procédés de fabrication mécanique", "type": "common"}, {"name": "Conception de circuits électroniques", "type": "common"}, {"name": "Automatique linéaire", "type": "common"}, {"name": "Recherche opérationnelle pour le génie industriel", "type": "common"}, {"name": "Compétences artistiques et culturelles", "type": "common"}, {"name": "Langues étrangères (anglais /français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Production et stockage de l''énergie", "type": "common"}, {"name": "Management de projet et de l''innovation", "type": "common"}, {"name": "Statistique décisionnelle", "type": "common"}, {"name": "Efficacité énergétique en milieu industriel", "type": "common"}, {"name": "Maintenance des systèmes industriels", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Electricité industrielle et automatisme", "type": "common"}, {"name": "Entreprenariat et gestion des entreprises", "type": "common"}, {"name": "Management de production", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Mini projet", "type": "common"}, {"name": "Management de projet et entrepreneuriat", "type": "common"}, {"name": "Management qualité", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Industrie 4.0", "type": "common"}, {"name": "Lean manufacturing et amélioration des processus", "type": "common"}, {"name": "Logistique et suply chain Management", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Ergonomie et HSE (Hygiène, Sécurité, Environnement)", "type": "common"}, {"name": "Supervision des systèmes industriels", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Production industrielle, maintenance industrielle, management de projet, qualité industrielle, sécurité et environnement (QSE), logistique et supply chain, organisation et optimisation des processus, gestion des opérations, amélioration continue et lean management, conseil et ingénierie industrielle.', 'Génie Industriel, Management Industriel, Amélioration Continue, Lean Manufacturing, Logistique, Supply Chain, Maintenance, Qualité HSE, Production, Optimisation des performances, Ingénierie des systèmes, ERP, Gestion de projet.');
INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GMSI', 'GMSI', 'La filière "Mécatronique et Systèmes Intelligents" combine la mécanique, l''électronique, l''informatique et l''automatique pour concevoir des systèmes intégrés et intelligents. Elle forme des ingénieurs capables de développer des robots, des machines autonomes, et des dispositifs embarqués. Les étudiants apprennent à maîtriser la modélisation, la programmation, et l''optimisation des systèmes complexes. Cette formation prépare à des carrières dans l''automobile, l''aéronautique, la robotique et les technologies de pointe. A la fin de cette formation, les lauréats doivent être capables de : Maîtriser le fonctionnement et augmenter les performances des systèmes mécatroniques. Concevoir et mettre au point des solutions mécatroniques. Conduire une équipe d''innovation dans le domaine de la mécatronique. Superviser, maintenir et développer un système mécatronique. Développer des solutions en mécatronique de l''automobile, de l''avion et des systèmes de production des énergies renouvelables. Systèmes robotisés et intelligents. Concevoir et augmenter la performance des systèmes embarqués. Concevoir, développer et maintenir des Optimiser une chaîne de production et améliorer la productivité. Conduire un changement et gérer les contraintes technologiques. Faire partie d''une équipe mixte de conception et de fabrication intégrées de systèmes mécatroniques.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Electronique Numérique", "type": "common"}, {"name": "Conception des Systèmes Mécaniques", "type": "common"}, {"name": "Systèmes Analogiques Avancés", "type": "common"}, {"name": "Programmation Orientée Objet en C++", "type": "common"}, {"name": "Systèmes de Mesure et Conception Expérimentale", "type": "common"}, {"name": "Algorithmique et Programmation en Python", "type": "common"}, {"name": "Langues Étrangères (Anglais/Français)", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Programmation des microcontrôleurs CORTEX M4", "type": "common"}, {"name": "Mécanique des Milieux Continues et Mécanique des Fluides", "type": "common"}, {"name": "Électronique de Puissance", "type": "common"}, {"name": "Électrotechnique", "type": "common"}, {"name": "Propriétés Mécaniques et Thermiques des Matériaux", "type": "common"}, {"name": "Créativité visuelle et innovation numérique", "type": "common"}, {"name": "Traitement du signal et simulation de circuits électroniques", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Base de Données et Réseaux Informatiques", "type": "common"}, {"name": "Systèmes Hydrauliques et Pneumatiques", "type": "common"}, {"name": "Calcul des Structures et RDM", "type": "common"}, {"name": "Systèmes Embarqués pour l''Automobile et Automate Programmable", "type": "common"}, {"name": "Systèmes Asservis", "type": "common"}, {"name": "Intelligence Artificielle et ses Applications", "type": "common"}, {"name": "Langues Étrangères (Anglais/Français)", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Informatique Embarquée", "type": "common"}, {"name": "Circuits programmables", "type": "common"}, {"name": "Capteurs intelligents industriels et chaine d''acquisition", "type": "common"}, {"name": "Maintenance 4.0", "type": "common"}, {"name": "Management de projet et entrepreneuriat", "type": "common"}, {"name": "Management intégré qualité, sécurité et environnement", "type": "common"}, {"name": "Mini projets", "type": "common"}, {"name": "Langues étrangères (français /anglais)", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Pilotage des performances et excellence opérationnelle", "type": "common"}, {"name": "Systèmes mécatroniques de l''automobile", "type": "common"}, {"name": "Robotique et systèmes intelligents", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Outils de modélisation et simulation automobile", "type": "common"}, {"name": "Internet des objets", "type": "common"}, {"name": "Commande intelligente", "type": "common"}, {"name": "Langues étrangères (français /anglais)", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Chef de projet en systèmes mécatroniques, gestion de maintenance et sûreté de fonctionnement, ingénieur en conception et développement mécatronique, bureaux d’études, industrie automobile, industrie aéronautique, énergies renouvelables, robotique industrielle, ingénieur-conseil.', 'Mécatronique, Systèmes Intelligents, Robotique, Automatique, Systèmes Embarqués, Mécanique, Electronique, Informatique, Automobile, Aéronautique, Energies Renouvelables, Maintenance, IA. ');
INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GPMA', 'GPMA', 'La filière génie des procédés et matériaux avancés a pour objectifs de répondre au marché de l''emploi avec plus d''ouverture vers la culture projet et le monde industriel. L''ingénieur en Génie des Procédés & Matériaux Avancés est fondamentalement un manager de la production, ouvert sur l''international. Il est capable de concevoir, d''implanter et de piloter un système de production en tenant compte des caractéristiques scientifiques, technologiques, économiques et humaines. Il participe à l''organisation de l''entreprise, en respectant les principes de durabilité et de respect de l''environnement. Il exploite ses connaissances au service de la performance, de la sécurité et de la qualité. Sa compétence s''étend des installations jusqu''aux produits, en passant par les relations et les informations mises en jeu lors de la production.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Opérations unitaires", "type": "common"}, {"name": "Physico-chimie des matériaux solides", "type": "common"}, {"name": "Instrumentation, mesures et plan d''expérience", "type": "common"}, {"name": "Résistance des matériaux et simulation numérique par éléments finis", "type": "common"}, {"name": "Systèmes thermiques et énergétiques", "type": "common"}, {"name": "Algorithmique et programmation en Python", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Echangeurs de chaleur industriels et machines hydrauliques", "type": "common"}, {"name": "Energies renouvelables", "type": "common"}, {"name": "Techniques de caractérisation des matériaux", "type": "common"}, {"name": "Recherche opérationnelle pour le génie industriel", "type": "common"}, {"name": "Automatique linéaire", "type": "common"}, {"name": "Algorithmique et programmation en Python", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Cristallisation industrielle et filtration", "type": "common"}, {"name": "Pilotage des performances et excellence opérationnelle", "type": "common"}, {"name": "Procédés de l''environnement et dessalement de l''eau de mer", "type": "common"}, {"name": "Statistique décisionnelle", "type": "common"}, {"name": "Métallurgie et traitement de surface", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Technologie des matériaux céramiques", "type": "gi"}, {"name": "Propriétés mécaniques et thermiques des matériaux", "type": "gi"}, {"name": "Commande des procédés industriels", "type": "gidia"}, {"name": "Génie réacteurs chimiques / Milieux poreux et dispersés", "type": "gidia"}, {"name": "Théories et pratiques des fours et des sécheurs industriels", "type": "gidia"}, {"name": "Management des entreprises et de projets", "type": "common"}, {"name": "Management de production", "type": "common"}, {"name": "Management intégré qualité, sécurité et environnement", "type": "common"}, {"name": "Mini projet", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Protection anticorrosion par revêtements", "type": "gi"}, {"name": "Matériaux durables et procédés de fabrication additive", "type": "gi"}, {"name": "Matériaux innovants, intelligents et nouvelles technologies", "type": "gi"}, {"name": "Matériaux composites et polymères", "type": "gi"}, {"name": "Stockage d''énergie et audit énergétique des procédés industriels", "type": "gidia"}, {"name": "Simulation des procédés industriels", "type": "gidia"}, {"name": "Cycle de vie, impact environnemental et sécurité des procédés", "type": "gidia"}, {"name": "Réalité virtuelle et réalité augmentée", "type": "gidia"}, {"name": "Technologies hydrogène et matériaux énergétiques", "type": "gidia"}, {"name": "Industrie 4.0", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de Fin d''Etudes (PFE)", "type": "common"}]}]}]', 'Conduite des procédés industriels, qualité industrielle, gestion énergétique et environnementale, sécurité industrielle, production, recherche et développement (R&D), services technico-commerciaux, après-vente, vente industrielle, achats techniques.', 'Génie des Procédés, Matériaux Avancés, Management de Production, Durabilité, R&D, Qualité HSE, Procédés Industriels, Matériaux Innovants, Digitalisation, Industrie 4.0, Simulation, Corrosion, Composites.');
INSERT INTO specialties (code, name, description, subjects, career_paths, additional_info) VALUES ('GTR', 'GTR', 'La filière Génie de Télécommunication et Réseaux (GTR) de l''ENSA-Safi forme des ingénieurs spécialisés en télécommunications et réseaux pour répondre aux besoins croissants des industries et services. Les étudiants y acquièrent des compétences en conception, implantation et gestion des réseaux, ainsi qu''en traitement du signal et protocoles de communication. La formation met un accent particulier sur la sécurité des réseaux et de l''Internet des objets (IoT), face aux défis croissants en cybersécurité. Structurée sur les quatre derniers semestres, elle combine enseignements techniques et matières spécifiques pour préparer des professionnels polyvalents et hautement qualifiés dans le domaine des TIC.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Théorie de l''information et codage", "type": "common"}, {"name": "Signaux et systèmes", "type": "common"}, {"name": "Electronique analogique", "type": "common"}, {"name": "Mathématiques Appliquées pour l''ingénieur", "type": "common"}, {"name": "Système d''information", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}, {"name": "Systèmes de Gestion de Contenu (CMS)", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Architecture des Systèmes", "type": "common"}, {"name": "Systèmes de Communications Analogiques", "type": "common"}, {"name": "Propagation et Antennes", "type": "common"}, {"name": "Probabilités et Processus stochastiques", "type": "common"}, {"name": "Introduction aux réseaux informatiques", "type": "common"}, {"name": "Culture and Art skills", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Electronique numérique", "type": "common"}, {"name": "Réseaux optiques et sécurité des données", "type": "common"}, {"name": "Ingénierie de la Décision et Optimisation par la Recherche Opérationnelle (IDORO)", "type": "common"}, {"name": "Transmission Numérique en Bande de Base", "type": "common"}, {"name": "Techniques de Modulations Numériques", "type": "common"}, {"name": "Langues Etrangères (Français /Anglais)", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Administration Avancée des Systèmes et Réseaux sous GNU/Linux", "type": "common"}, {"name": "Réseaux cellulaires et planification mobile", "type": "common"}, {"name": "Systèmes de communication radio", "type": "common"}, {"name": "Traitement d''images (TI)", "type": "common"}, {"name": "Génie logiciel et systèmes intelligents", "type": "common"}, {"name": "Langues Etrangères (Français /Anglais)", "type": "common"}, {"name": "Management de Projet et entrepreneuriat", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Cryptographie et sécurité des systèmes d''information et réseaux (CSSIR)", "type": "common"}, {"name": "Automatisation robotisée des processus (RPA)", "type": "common"}, {"name": "Sécurité des objets connectés (IOT)", "type": "common"}, {"name": "Cloud Computing", "type": "common"}, {"name": "technologie de réseau étendu", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}, {"name": "Employment Skills", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Ingénieur réseaux, ingénieur télécommunications, administrateur systèmes et réseaux, ingénieur cybersécurité, spécialiste en sécurité des réseaux, ingénieur IoT, développeur et intégrateur de solutions, consultant en réseaux et télécoms, entrepreneur technologique, chercheur en nouvelles technologies.', 'Télécommunications, Réseaux, Cybersécurité, Internet des Objets (IoT), Ingénieur télécoms, Administration des réseaux, Sécurité des systèmes, Cloud Computing, Infrastructure réseau, Optimisation des réseaux mobiles, Consultant en cybersécurité, Développement et intégration, Virtualisation, Entrepreneuriat, Intelligence artificielle appliquée aux réseaux, Startups technologiques, Sociétés de services numériques (ESN), Innovation technologique, Infrastructure critique, Recherche et développement (R&D).');
